from typing import Optional

import typer
from ragapp import index as idx, search as srch, ingest as ing

app = typer.Typer(help="ragapp CLI")


@app.command()
def ingest(path: str) -> None:
    ing.run(path)


@app.command()
def index(backend: str = typer.Option("faiss", "--backend")) -> None:
    idx.build(backend)


@app.command()
def search(query: str, k: int = typer.Option(5, "-k")) -> None:
    srch.run(query, k=k)


if __name__ == "__main__":
    app()

